async (page) => {
  // Intercept WebSocket messages to track quest-related packets
  await page.evaluate(() => {
    window.__wsMessages = [];
    const origWS = window.WebSocket;
    // Try to hook into game.socket to listen to incoming messages
    const socket = window.game.socket;
    if (socket) {
      const socketKeys = Object.keys(socket).filter(k => !k.startsWith('_'));
      window.__socketKeys = socketKeys;

      // Look for packet handler methods  
      const handlers = socketKeys.filter(k => typeof socket[k] === 'function');
      window.__socketHandlers = handlers.slice(0, 20);
    }
  });

  const result = await page.evaluate(() => ({
    socketKeys: window.__socketKeys ? window.__socketKeys.slice(0, 15) : [],
    socketHandlers: window.__socketHandlers ? window.__socketHandlers.slice(0, 15) : []
  }));
  return JSON.stringify(result);
}

async (page) => {
  // Hook into questCallback to monitor server messages
  await page.evaluate(() => {
    const msgs = window.game.socket.messages;
    const origQuestCb = msgs.questCallback;
    window.__questCallbackLog = [];
    msgs.questCallback = function(...args) {
      window.__questCallbackLog.push({ t: Date.now(), args: JSON.stringify(args).slice(0, 500) });
      return origQuestCb.apply(this, args);
    };
    console.log('Quest callback hooked');
  });

  // Now walk toward the Programmer NPC and click them
  // Programmer is at (331, 890), I'm at (328, 892) - they're 3 east, 2 north from me
  // In the spawn building, they were at ~(810, 285) initially
  // Click to approach them
  await page.evaluate(({x, y}) => {
    const canvas = document.getElementById('canvas');
    canvas.dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, { x: 760, y: 290 });
  await page.waitForTimeout(3000);

  const log = await page.evaluate(() => window.__questCallbackLog);
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
  const programmer = parsed.nearby_entities.find(e => e.name === 'Programmer');

  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  return JSON.stringify({ log, pos: parsed.player_position, programmer: programmer ? {dist: programmer.distance} : null });
}

