async (page) => {
  // Hook ALL socket callbacks to monitor what happens during NPC dialogue
  await page.evaluate(() => {
    const msgs = window.game.socket.messages;
    window.__allMsgLog = [];
    const interestingCallbacks = ['questCallback', 'npcCallback', 'talkCallback', 'chatCallback', 'commandCallback'];

    for (const cb of Object.keys(msgs)) {
      if (typeof msgs[cb] === 'function') {
        const orig = msgs[cb];
        msgs[cb] = function(...args) {
          window.__allMsgLog.push({ cb, args: JSON.stringify(args).slice(0, 200) });
          return orig.apply(this, args);
        };
      }
    }
    console.log('All callbacks hooked');
  });

  // Walk south to avoid Batterfliess (click below my position)
  await page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, { x: 580, y: 580 });
  await page.waitForTimeout(4000);

  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
  return JSON.stringify({ pos: parsed.player_position, hp: parsed.player_stats.hp });
}

