async (page) => {
  // Re-click Village Girl to reactivate dialogue session
  await page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, { x: 565, y: 335 });
  await page.waitForTimeout(1500);

  // Set activeQuest to scavenger (Village Girl's quest)
  await page.evaluate(() => {
    const questMenu = window.game.menu.quest;
    const scavengerQuest = window.game.player.quests.scavenger;
    questMenu.activeQuest = scavengerQuest;
    console.log('Set activeQuest to:', scavengerQuest ? scavengerQuest.name : 'null');
  });

  // Immediately click quest button WITHOUT moving
  await page.evaluate(() => {
    document.getElementById('quest-button').click();
  });
  await page.waitForTimeout(2000);

  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
  const scavenger = parsed.quests.find(q => q.key === 'scavenger');
  const msgLog = await page.evaluate(() => window.__allMsgLog.filter(l => !['movementCallback','networkCallback','combatCallback','pointsCallback'].includes(l.cb)));

  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  return JSON.stringify({ scavenger, msgLog: msgLog.slice(0,5), pos: parsed.player_position, hp: parsed.player_stats.hp });
}

async (page) => {
  await page.evaluate(() => { window.__sentPackets = []; window.__allMsgLog = []; });

  // Village Girl appears to be at ~(620, 380) based on screenshot
  // Click her 4 times with delays, monitoring npcCallback
  const npcClicks = [];

  for (let i = 0; i < 4; i++) {
    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
    }, { x: 625, y: 380 });
    await page.waitForTimeout(800);

    const log = await page.evaluate(() => {
      const relevant = window.__allMsgLog.filter(l => l.cb === 'npcCallback' || l.cb === 'questCallback');
      window.__allMsgLog = [];
      return relevant;
    });
    npcClicks.push(log);
  }

  // Check quest button state
  const btnDisplay = await page.evaluate(() => getComputedStyle(document.getElementById('quest-button')).display);

  await page.screenshot({ path: '/tmp/kaetram_agent_3/state/screenshot.png', type: 'png' });
  return JSON.stringify({ npcClicks, btnDisplay });
}

